  (() => {
    const articles = $response.body || [];
    const q = ($input.query || '').toLowerCase();
    if (!q) return articles.slice(0, 3).map(a => ({ slug: a.slug, title: (a.translations?.en?.title || a.title), excerpt: (a.translations?.en?.excerpt || a.excerpt) }));
    const matches = articles.filter(a => {
      const t = JSON.stringify(a.translations || {}).toLowerCase();
      return t.includes(q) || (a.title || '').toLowerCase().includes(q);
    });
    return matches.slice(0, 3).map(a => ({ slug: a.slug, title: (a.translations?.en?.title || a.title), excerpt: (a.translations?.en?.excerpt || a.excerpt) }));
  })()
}}

