// Strip {{ESCALATE}} marker and set needs_human flag
const raw = $json.output || '';
const needsHuman = raw.includes('{{ESCALATE}}');
const clean = raw.replace(/\{\{ESCALATE\}\}/g, '').trim();
return [{
  json: {
    ...$json,
    output_clean: clean,
    needs_human: needsHuman,
  }
}];

